external_knowledge:
- "dawn of the mid-20th century" refers to the year 1940;
- "dawn of the 21st century" refers to the year 2020;
- "standing outside the labor force" refers to individuals not in the labor force.

sql:
SELECT COUNT(*) 
FROM not_in_labor_force 
WHERE number_not_in_labor_force > 42447;

SELECT total_labor_force, percent_population_in_labor_force
FROM labor_force
WHERE total_labor_force > 60000;

SELECT year_id
FROM labor_force
ORDER BY total_labor_force DESC;

SELECT total_labor_force 
FROM labor_force
LIMIT 1;

SELECT total_population
FROM population
WHERE year_id = (SELECT year_id FROM years WHERE is_current_year = 1);

external_knowledge:
- "Agriculture" refers to the sector involving farming, livestock, and forestry;
- "Non-agriculture" includes industries such as manufacturing, services, and technology;
- "Other" sectors encompass any employment not classified as agriculture or non-agriculture.

sql:
SELECT AVG(e.total_employed_population + u.number_unemployed) AS average_total_labor_force
FROM employment e
JOIN unemployment u ON e.year_id = u.year_id;

SELECT ROUND(AVG(male_labor_force * 100.0 / total_labor_force)) AS average_male_labor_force_percentage
FROM labor_force
WHERE total_labor_force IS NOT NULL AND male_labor_force IS NOT NULL;
